#!/usr/bin/env node
//
// CI guard: fail fast if package-lock.json was regenerated by an
// out-of-range npm version. npm 11+ produces lockfiles that pass
// local `npm install` cleanly but break Cloudflare Workers Builds'
// `npm ci` (which runs npm 10.9.x in strict mode and rejects them
// with "Missing <transitive> from lock file").
//
// engine-strict + engines.npm in package.json catch this on `npm
// install`, but only if the contributor has both pieces wired. This
// script is the read-side belt-and-braces — runs in CI before any
// install step and refuses to proceed on the wrong lockfile shape.
//
// Run via `npm run check:lockfile`.
//
// Bumping the expected version: when CF Workers Builds upgrades its
// runner to npm 11+ and we move the engines pin, also bump
// EXPECTED_VERSION here in the same commit.

import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const EXPECTED_VERSION = 3;

const here = dirname(fileURLToPath(import.meta.url));
const lockfilePath = resolve(here, "..", "package-lock.json");

let lock;
try {
  lock = JSON.parse(readFileSync(lockfilePath, "utf8"));
} catch (err) {
  console.error(`check-lockfile-version: failed to read ${lockfilePath}`);
  console.error(err.message);
  process.exit(2);
}

const actual = lock.lockfileVersion;
if (actual !== EXPECTED_VERSION) {
  console.error(
    `check-lockfile-version: lockfileVersion=${actual}, expected ${EXPECTED_VERSION}.`,
  );
  console.error(
    "Likely cause: package-lock.json was regenerated by npm 11+. CF Workers Builds runs npm 10.9.x and will reject this on `npm ci`.",
  );
  console.error(
    "Fix: install npm 10.9.x (`npm i -g npm@10.9.2`), delete node_modules + package-lock.json, then `npm install`.",
  );
  process.exit(1);
}

console.log(`check-lockfile-version: lockfileVersion=${actual} ✓`);
